import{_ as t,o as a,c as o,a2 as r}from"./chunks/framework.B8zgMDLd.js";const u=JSON.parse('{"title":"Editor","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/editor.md","filePath":"concepts/editor.md"}'),i={name:"concepts/editor.md"};function n(d,e,s,c,l,h){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="editor" tabindex="-1">Editor <a class="header-anchor" href="#editor" aria-label="Permalink to &quot;Editor&quot;">​</a></h1><p>Tolaria offers a rich editor for daily writing and a raw Markdown mode for exact file control. Both modes write back to the same Markdown file.</p><h2 id="rich-editing" tabindex="-1">Rich Editing <a class="header-anchor" href="#rich-editing" aria-label="Permalink to &quot;Rich Editing&quot;">​</a></h2><p>The rich editor supports blocks, slash commands, wikilinks, tables, code blocks, images, Mermaid diagrams, LaTeX-style math, and markdown-backed whiteboards.</p><p>Use it when you want to write and reorganize quickly without thinking about Markdown syntax.</p><h2 id="raw-mode" tabindex="-1">Raw Mode <a class="header-anchor" href="#raw-mode" aria-label="Permalink to &quot;Raw Mode&quot;">​</a></h2><p>Raw mode shows the Markdown source directly. Use it when you need to edit YAML frontmatter, repair unusual Markdown, or make an exact text change.</p><p>Toggle raw mode with <code>Cmd+\\</code> on macOS or <code>Ctrl+\\</code> on Windows and Linux.</p><h2 id="table-of-contents" tabindex="-1">Table Of Contents <a class="header-anchor" href="#table-of-contents" aria-label="Permalink to &quot;Table Of Contents&quot;">​</a></h2><p>The table of contents panel builds an outline from headings in the current note. It is useful for long notes, procedures, research files, and generated documents. Toggle it with <code>Cmd+Shift+T</code> on macOS or <code>Ctrl+Shift+T</code> on Windows and Linux.</p><h2 id="width" tabindex="-1">Width <a class="header-anchor" href="#width" aria-label="Permalink to &quot;Width&quot;">​</a></h2><p>Notes can use normal or wide editor width. Set the default in Settings, or override an individual note from the editor toolbar.</p>',12)])])}const f=t(i,[["render",n]]);export{u as __pageData,f as default};
